   803→// Comprehensive video interview analysis combining all signals
   804→async function analyzeVideoInterviewResponse(question, transcription, frames, durationSeconds, keyPoints, options = {}) {
   805→  const audioData = options.audioData || null;
   806→  let finalTranscription = transcription;
   807→
   808→  // Step 1: If audio data available, try Whisper for more accurate transcription
   809→  let whisperResult = null;
   810→  if (audioData) {
   811→    try {
   812→      console.log('[ai] Transcribing audio with Whisper...');
   813→      whisperResult = await transcribeAudioWithWhisper(audioData, options);
   814→      if (whisperResult && whisperResult.text && whisperResult.text.trim().length > 20) {
   815→        finalTranscription = whisperResult.text;
   816→        console.log(`[ai] Whisper transcription: ${finalTranscription.length} chars (replaced browser transcription)`);
   817→      } else {
   818→        console.log('[ai] Whisper result too short, keeping browser transcription');
   819→      }
   820→    } catch (err) {
   821→      console.warn('[ai] Whisper failed, using browser transcription:', err.message);
   822→    }
   823→  }
   824→
   825→  // Step 2: Run all analyses in parallel
   826→  const analysisPromises = [
   827→    analyzeInterviewResponse(question, finalTranscription, keyPoints, options),
   828→    generateInterviewCoaching(question, finalTranscription, { score: 5, strengths: [], improvements: [] }, options),
   829→    analyzeVideoPresentation(frames, options)
   830→  ];
   831→
   832→  // Add voice quality analysis if we have audio
   833→  if (audioData) {
   834→    analysisPromises.push(analyzeVoiceQuality(finalTranscription, durationSeconds, options));
   835→  }
   836→
   837→  const results = await Promise.all(analysisPromises);
   838→  const [contentAnalysis, contentCoaching, videoAnalysis] = results;
   839→  const voiceAnalysis = audioData ? results[3] : null;
   840→
   841→  // Algorithmic speech analysis
   842→  const speechAnalysis = analyzeSpeechPatterns(finalTranscription, durationSeconds);
   843→
   844→  // Calculate category scores
   845→  const contentScore = contentAnalysis.score || 5;
   846→  let communicationScore = speechAnalysis.communication_score || 5;
   847→  const presentationScore = videoAnalysis.overall_presentation || 5;
   848→
   849→  // If voice analysis available, blend its score into communication
   850→  if (voiceAnalysis && voiceAnalysis.overall_voice_score) {
   851→    // 60% algorithmic speech analysis, 40% AI voice quality
   852→    communicationScore = Math.round(
