   585→// Analyze speech transcription for communication quality
   586→function analyzeSpeechPatterns(transcription, durationSeconds) {
   587→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   588→  const wordCount = words.length;
   589→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   590→
   591→  // Filler word detection
   592→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   593→  const fillerCounts = {};
   594→  let totalFillers = 0;
   595→  const lowerTranscription = transcription.toLowerCase();
   596→
   597→  for (const filler of fillerWords) {
   598→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   599→    const matches = lowerTranscription.match(regex);
   600→    if (matches && matches.length > 0) {
   601→      fillerCounts[filler] = matches.length;
   602→      totalFillers += matches.length;
   603→    }
   604→  }
   605→
   606→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   607→
   608→  // Pace analysis
   609→  let paceAssessment = 'good';
   610→  let paceFeedback = '';
   611→  if (wpm < 100) {
   612→    paceAssessment = 'too_slow';
   613→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   614→  } else if (wpm < 120) {
   615→    paceAssessment = 'slightly_slow';
   616→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   617→  } else if (wpm <= 160) {
   618→    paceAssessment = 'good';
   619→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   620→  } else if (wpm <= 180) {
   621→    paceAssessment = 'slightly_fast';
   622→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   623→  } else {
   624→    paceAssessment = 'too_fast';
   625→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   626→  }
   627→
   628→  // Sentence structure analysis
   629→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   630→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   631→
   632→  // Communication score (1-10)
   633→  let communicationScore = 7;
   634→  // Penalize for filler words
   635→  if (fillerRate > 5) communicationScore -= 2;
   636→  else if (fillerRate > 3) communicationScore -= 1;
   637→  // Penalize for bad pace
   638→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   639→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   640→  // Reward for good sentence structure
   641→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   642→  // Penalize for very short responses
   643→  if (wordCount < 50) communicationScore -= 2;
   644→  else if (wordCount < 100) communicationScore -= 1;
   645→  // Reward for substantial responses
   646→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   647→
   648→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   649→
   650→  return {
   651→    word_count: wordCount,
   652→    duration_seconds: durationSeconds,
   653→    words_per_minute: wpm,
   654→    filler_words: fillerCounts,
   655→    total_fillers: totalFillers,
   656→    filler_rate: Math.round(fillerRate * 10) / 10,
   657→    pace: {
   658→      assessment: paceAssessment,
   659→      wpm,
   660→      feedback: paceFeedback
   661→    },
   662→    sentence_count: sentences.length,
   663→    avg_sentence_length: avgSentenceLength,
   664→    communication_score: communicationScore,
   665→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   666→  };
   667→}
   668→
   669→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   670→  const tips = [];
   671→
   672→  if (fillerRate > 3) {
   673→    const topFillers = Object.entries(fillerCounts)
   674→      .sort((a, b) => b[1] - a[1])
   675→      .slice(0, 3)
   676→      .map(([word, count]) => `"${word}" (${count}x)`);
   677→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   678→  }
   679→
   680→  if (wpm > 160) {
   681→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   682→  } else if (wpm < 110) {
   683→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   684→  }
   685→
   686→  if (wordCount < 80) {
   687→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   688→  }
   689→
   690→  if (tips.length === 0) {
   691→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   692→  }
   693→
   694→  return tips;
   695→}
