   697→// Transcribe audio via OpenAI Whisper (more accurate than browser SpeechRecognition)
   698→async function transcribeAudioWithWhisper(audioBase64, options = {}) {
   699→  try {
   700→    // Strip full data URL prefix including codec params (e.g., data:audio/webm;codecs=opus;base64,)
   701→    const base64Data = audioBase64.replace(/^data:audio\/[^;]+(?:;[^;]*)*;base64,/, '');
   702→    const buffer = Buffer.from(base64Data, 'base64');
   703→
   704→    // Extract MIME type (e.g., audio/webm from data:audio/webm;codecs=opus;base64,)
   705→    const mimeMatch = audioBase64.match(/^data:(audio\/[^;]+)/);
   706→    const mimeType = mimeMatch ? mimeMatch[1] : 'audio/webm';
   707→    const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm';
   708→    console.log(`[whisper] Audio format: ${mimeType}, ext: ${ext}, buffer size: ${buffer.length} bytes`);
   709→
   710→    const formData = new FormData();
   711→    formData.append('file', buffer, {
   712→      filename: `recording.${ext}`,
   713→      contentType: mimeType
   714→    });
   715→    formData.append('model', 'whisper-1');
   716→    formData.append('response_format', 'verbose_json');
   717→
   718→    const baseUrl = process.env.OPENAI_BASE_URL || 'https://api.openai.com/v1';
