   724→
   725→    const res = await fetch(`${baseUrl}/audio/transcriptions`, {
   726→      method: 'POST',
   727→      headers,
   728→      body: formData
   729→    });
   730→
   731→    if (!res.ok) {
   732→      const errText = await res.text();
