  1043→// Text-to-Speech via OpenAI TTS API with database caching
  1044→// Returns a Buffer of audio data (mp3 format)
  1045→// Caches audio in tts_cache table — same text returns cached audio without API call
  1046→async function textToSpeech(text, options = {}) {
