  1059→
  1060→    // Check cache first — serves audio even when daily token limit is exhausted
  1061→    try {
  1062→      const cached = await pool.query(
  1063→        'SELECT audio_data FROM tts_cache WHERE text_hash = $1',
  1064→        [cacheKey]
  1065→      );
  1066→      if (cached.rows.length > 0 && cached.rows[0].audio_data) {
  1067→        const buf = Buffer.from(cached.rows[0].audio_data);
  1068→        console.log(`[tts] Cache HIT: ${truncatedText.length} chars, ${buf.length} bytes (voice: ${voice})`);
  1069→        return buf;
  1070→      }
