  1072→      // Cache miss or table doesn't exist yet — continue to API
  1073→      console.log(`[tts] Cache check failed (${cacheErr.message}), proceeding to API`);
  1074→    }
  1075→
  1076→    console.log(`[tts] Cache MISS — generating speech: ${truncatedText.length} chars, voice: ${voice}`);
  1077→
  1078→    const baseUrl = process.env.OPENAI_BASE_URL || 'https://api.openai.com/v1';
  1079→    const apiKey = process.env.OPENAI_API_KEY;
