// AI interviewer conducts a conversational interview turn
async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
  // BUG FIX: Only send last 8 turns for speed (full history makes prompts huge and slow)
  const recentConvo = conversation.slice(-8);
  const convoText = recentConvo.map(turn => {
    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
    return `CANDIDATE: ${turn.text}`;
  }).join('\n\n');

  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
  const nextQuestionHint = remainingQuestions.length > 0
    ? `\nNEXT QUESTION: ${remainingQuestions[0].question_text} (${remainingQuestions[0].question_type})`
    : '';

  const prompt = `Mock interview for "${targetRole}". Question ${candidateTurnCount + 1} of ~8.

RECENT CONVERSATION:
${convoText}
${nextQuestionHint}

React briefly to the last answer (1 sentence), then ask your next question.
Actions: "follow_up" (vague answer), "challenge" (test deeper), "transition" (solid, move on), "wrap_up" (8+ exchanges done).

Return JSON: {"reaction":"...","action":"...","question":"...","score_hint":1-10,"notes":"..."}`;

  const result = await chat(prompt, {
    system: `Expert ${targetRole} interviewer. Brief, natural reactions. Push for specifics on vague answers. Always valid JSON.`,
    maxTokens: 1024,
    subscriptionId: options.subscriptionId
  });

  try {
    return JSON.parse(result);
  } catch (e) {
    const match = result.match(/\{[\s\S]*\}/);
    if (match) return JSON.parse(match[0]);
    throw new Error('Failed to generate interview turn');
  }
}

